// intake-store-input — Step 1: Validate and Normalize
// Receives: { intake_payload: {...}, runtime_config: {...} }
// Validates required fields, applies defaults, normalizes values.

const input = $input.first().json;
const payload = input.intake_payload || {};
const runtimeConfig = input.runtime_config;

if (!runtimeConfig || !runtimeConfig.project_root) {
  throw new Error('MISSING_RUNTIME_CONFIG: runtime_config.project_root is required');
}

// ── Required field validation ─────────────────────────────────────────────
const REQUIRED_FIELDS = [
  'project_id',
  'project_name',
  'primary_market',
  'primary_language',
  'primary_currency',
  'vertical',
  'price_positioning',
  'publish_mode',
];

const missing = REQUIRED_FIELDS.filter((f) => !payload[f] || !String(payload[f]).trim());
if (missing.length > 0) {
  throw new Error(
    `Intake validation failed. Missing required fields: ${missing.join(', ')}`
  );
}

// ── project_id pattern validation ─────────────────────────────────────────
const projectId = payload.project_id.toLowerCase().trim();
if (!/^[a-z0-9-]+$/.test(projectId)) {
  throw new Error(
    `project_id must match ^[a-z0-9-]+$ (lowercase, numbers, hyphens only). Got: "${payload.project_id}"`
  );
}

// ── Enum validations ──────────────────────────────────────────────────────
const VALID_MARKETS       = ['DE', 'AT', 'CH', 'DACH', 'EU', 'US', 'UK', 'Global'];
const VALID_LANGUAGES     = ['de', 'en', 'fr', 'it', 'es'];
const VALID_CURRENCIES    = ['EUR', 'USD', 'GBP', 'CHF'];
const VALID_VERTICALS     = ['consumer-tech-accessories', 'fashion-textiles', 'pet-products', 'home-living', 'fitness-accessories', 'beauty', 'general-commerce', 'other'];
const VALID_PRICE_POS     = ['budget', 'mass-market', 'mass-premium', 'premium', 'luxury', 'to-be-defined'];
const VALID_PUBLISH_MODES = ['no-publish', 'draft-only', 'draft-and-review'];

if (!VALID_MARKETS.includes(payload.primary_market)) {
  throw new Error(`primary_market "${payload.primary_market}" not in: ${VALID_MARKETS.join(', ')}`);
}
if (!VALID_LANGUAGES.includes(payload.primary_language)) {
  throw new Error(`primary_language "${payload.primary_language}" not in: ${VALID_LANGUAGES.join(', ')}`);
}
if (!VALID_CURRENCIES.includes(payload.primary_currency)) {
  throw new Error(`primary_currency "${payload.primary_currency}" not in: ${VALID_CURRENCIES.join(', ')}`);
}
if (!VALID_VERTICALS.includes(payload.vertical)) {
  throw new Error(`vertical "${payload.vertical}" not in: ${VALID_VERTICALS.join(', ')}`);
}
if (!VALID_PRICE_POS.includes(payload.price_positioning)) {
  throw new Error(`price_positioning "${payload.price_positioning}" not in: ${VALID_PRICE_POS.join(', ')}`);
}
if (!VALID_PUBLISH_MODES.includes(payload.publish_mode)) {
  throw new Error(`publish_mode "${payload.publish_mode}" not in: ${VALID_PUBLISH_MODES.join(', ')}`);
}

// ── Apply defaults and normalize ─────────────────────────────────────────
const VALID_STORE_TYPES = ['single-brand-store', 'multi-product-store', 'category-specialist', 'editorial-commerce-store', 'general-commerce-store'];
const VALID_BIZ_MODELS  = ['ecommerce', 'dropshipping', 'hybrid', 'other'];

const normalized = {
  project_id:                 projectId,
  project_name:               payload.project_name.trim(),
  primary_market:             payload.primary_market,
  target_markets:             Array.isArray(payload.target_markets) ? payload.target_markets : [payload.primary_market],
  primary_language:           payload.primary_language,
  languages:                  Array.isArray(payload.languages) ? payload.languages : [payload.primary_language],
  primary_currency:           payload.primary_currency,
  currencies:                 Array.isArray(payload.currencies) ? payload.currencies : [payload.primary_currency],
  vertical:                   payload.vertical,
  store_type:                 VALID_STORE_TYPES.includes(payload.store_type) ? payload.store_type : 'multi-product-store',
  business_model:             VALID_BIZ_MODELS.includes(payload.business_model) ? payload.business_model : 'ecommerce',
  price_positioning:          payload.price_positioning,
  brand_role:                 payload.brand_role || null,
  tone_of_voice:              payload.tone_of_voice || null,
  trust_style:                payload.trust_style || null,
  conversion_style:           payload.conversion_style || null,
  objection_handling_style:   payload.objection_handling_style || null,
  competitor_urls:            Array.isArray(payload.competitor_urls) ? payload.competitor_urls : [],
  desired_style_hints:        Array.isArray(payload.desired_style_hints) ? payload.desired_style_hints : [],
  forbidden_styles:           Array.isArray(payload.forbidden_styles) ? payload.forbidden_styles : [],
  must_not_feel_like:         payload.must_not_feel_like || null,
  must_feel_like:             payload.must_feel_like || null,
  seo_goal:                   payload.seo_goal || 'hybrid',
  aeo_goal:                   payload.aeo_goal || 'hybrid',
  faq_intensity:              payload.faq_intensity || 'balanced',
  knowledge_content_priority: payload.knowledge_content_priority || 'supporting',
  motion_level_preference:    payload.motion_level_preference || 'subtle',
  scroll_animation_preference:payload.scroll_animation_preference || 'light',
  hero_video_allowed:         typeof payload.hero_video_allowed === 'boolean' ? payload.hero_video_allowed : false,
  video_usage_preference:     payload.video_usage_preference || 'supporting-only',
  performance_priority:       payload.performance_priority || 'balanced',
  manual_review_required:     typeof payload.manual_review_required === 'boolean' ? payload.manual_review_required : true,
  publish_mode:               payload.publish_mode,
  special_notes:              payload.special_notes ? String(payload.special_notes).trim() : null,
};

return [{ json: { normalized_intake_payload: normalized, runtime_config: runtimeConfig } }];

// intake-store-input — Step 2: Create Project Directories + Initial Checkpoint
// Creates: {project_root}/{project_id}/, .runtime/, .runtime/quarantine/
// Writes the initial checkpoint marking intake-store-input as complete.

const fs   = require('fs');
const path = require('path');

const input          = $input.first().json;
const normalized     = input.normalized_intake_payload;
const runtimeConfig  = input.runtime_config;
const projectId      = normalized.project_id;
const projectRoot    = runtimeConfig.project_root;

// ── Create directories ────────────────────────────────────────────────────
const projectDir    = path.join(projectRoot, projectId);
const runtimeDir    = path.join(projectDir, '.runtime');
const quarantineDir = path.join(runtimeDir, 'quarantine');

fs.mkdirSync(projectDir,    { recursive: true });
fs.mkdirSync(runtimeDir,    { recursive: true });
fs.mkdirSync(quarantineDir, { recursive: true });

// ── Build execution_run_id ────────────────────────────────────────────────
const now = new Date();
const pad = (n) => String(n).padStart(2, '0');
const runId = [
  'run',
  `${now.getFullYear()}${pad(now.getMonth() + 1)}${pad(now.getDate())}`,
  `${pad(now.getHours())}${pad(now.getMinutes())}${pad(now.getSeconds())}`,
].join('-');

// ── Write initial checkpoint ──────────────────────────────────────────────
const checkpoint = {
  schema_version:          '1.0',
  project_id:              projectId,
  execution_run_id:        runId,
  chain_start_timestamp:   now.toISOString(),
  last_updated_timestamp:  now.toISOString(),
  chain_status:            'IN_PROGRESS',
  completed_workflows: [
    {
      workflow_id:      'intake-store-input',
      completed_at:     now.toISOString(),
      output_artifact:  null,
      status:           'SUCCESS',
    },
  ],
  failed_at:               null,
  next_workflow:           'import-shopify-data',
  review_gate_status:      'NOT_REACHED',
  review_gate_approved_at: null,
  env:                     runtimeConfig.env,
  llm_model_used:          runtimeConfig.llm_model || null,
  shopify_api_version_used:runtimeConfig.shopify_api_version || null,
  notes:                   [],
};

const checkpointPath = path.join(runtimeDir, 'checkpoint.json');
const checkpointTmp  = checkpointPath + '.tmp';
fs.writeFileSync(checkpointTmp, JSON.stringify(checkpoint, null, 2), 'utf8');
fs.renameSync(checkpointTmp, checkpointPath);

// ── Write initial execution log entry ─────────────────────────────────────
const logPath = path.join(runtimeDir, 'execution-log.json');
const log = { entries: [
  {
    timestamp:         now.toISOString(),
    execution_run_id:  runId,
    level:             'INFO',
    event_type:        'CHAIN_START',
    workflow_id:       'intake-store-input',
    message:           `Chain started for project: ${projectId} (env: ${runtimeConfig.env})`,
  },
  {
    timestamp:         now.toISOString(),
    execution_run_id:  runId,
    level:             'INFO',
    event_type:        'WORKFLOW_SUCCESS',
    workflow_id:       'intake-store-input',
    message:           `intake-store-input completed. Project directories created at: ${projectDir}`,
  },
] };
const logTmp = logPath + '.tmp';
fs.writeFileSync(logTmp, JSON.stringify(log, null, 2), 'utf8');
fs.renameSync(logTmp, logPath);

return [{
  json: {
    project_id:              projectId,
    execution_run_id:        runId,
    normalized_intake_payload: normalized,
    runtime_config:          runtimeConfig,
    project_dir:             projectDir,
    status:                  'SUCCESS',
  },
}];
